/* ==========================================================================
   Responsive Breakpoints
   ========================================================================== */

@media (max-width: 768px) {
  /* Rich text */
  .cms-rich-text h1 {
    font-size: var(--itg-font-size-h1-mobile);
  }

  .cms-rich-text .section-title {
    font-size: var(--itg-font-size-h2-mobile);
