    font-size: var(--itg-font-size-h3-mobile);
  }

  .cms-rich-text table {
    font-size: var(--itg-font-size-table-mobile);
  }

  .cms-rich-text th,
  .cms-rich-text td {
    padding: 0.5rem;
  }

  /* Section group */
  .cms-section-group h1.section-title,
  .cms-section-group .section-title:first-child {
