}

.project-detail-meta-label {
  font-size: var(--itg-font-size-label);
  color: var(--itg-color-text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.project-detail-meta-value {
  font-size: var(--itg-font-size-body);
  color: var(--itg-color-primary);
  font-weight: 500;
}

.project-detail-section {
  margin-bottom: 2rem;
}

.project-detail-section-title {
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-h3);
  margin: 0 0 0.75rem;
}

.project-detail-abstract {
  font-size: var(--itg-font-size-body);
  line-height: var(--itg-line-height-body);
  color: var(--itg-color-text-dark);
  margin: 0;
}

.project-detail-students {
  font-size: var(--itg-font-size-body);
  line-height: var(--itg-line-height-meta);
  color: var(--itg-color-text);
  margin: 0;
}

@media (max-width: 768px) {
  .project-detail-title {
    font-size: var(--itg-font-size-h1-mobile);
  }

  .project-detail-meta {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 480px) {
  .project-detail-meta {
    grid-template-columns: 1fr;
  }
}


/* ---- base.css ---- */
.project-grid-card {
  background: var(--itg-color-white);
  border: 1px solid var(--itg-color-border);
  border-radius: var(--itg-radius-card);
  box-shadow: 0 10px 30px rgba(15, 45, 82, 0.08);
  overflow: hidden;
}

.project-grid-card + .project-grid-card {
  margin-top: 1.5rem;
}

.project-grid-card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 1rem;
  padding: 1.5rem 1.5rem 0;
}

.project-grid-card-title {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-h2);
}

.project-grid-card-copy {
  margin: 0.5rem 0 0;
  color: var(--itg-color-text-secondary);
  line-height: var(--itg-line-height-meta);
}

.project-grid-table-shell {
  padding: 1.25rem 1.5rem 1.5rem;
}

.project-grid-toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.project-grid-inline-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.project-grid-inline-actions--clustered {
  align-items: center;
  gap: 0.65rem 1rem;
}

.project-grid-toolbar-cluster {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.5rem;
}

@media (min-width: 641px) {
  .project-grid-inline-actions--clustered .project-grid-toolbar-cluster + .project-grid-toolbar-cluster {
    padding-left: 1rem;
    border-left: 1px solid var(--itg-color-border);
  }
}

.project-grid-controls {
  margin-bottom: 1.1rem;
}

.project-grid-controls-inner {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  width: 100%;
}

.project-grid-controls-row {
  display: flex;
  align-items: center;
  gap: 1rem 1.25rem;
  flex-wrap: wrap;
}

.project-grid-field-label {
  display: block;
  color: var(--itg-color-text-secondary);
  font-size: 0.6875rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  line-height: 1.2;
}

.project-grid-search-input {
  flex: 1;
  min-width: min(100%, 220px);
  border: 1px solid var(--itg-color-border);
  border-radius: 10px;
  padding: 0.65rem 0.95rem;
  font: inherit;
  font-size: var(--itg-font-size-small);
  color: var(--itg-color-text-dark);
  background: #fbfcfe;
}

.project-grid-search-input:focus {
  outline: 2px solid rgba(15, 45, 82, 0.18);
  border-color: var(--itg-color-primary);
}

.project-grid-controls-meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.75rem 1.25rem;
  flex-shrink: 0;
}

.project-grid-count {
  margin: 0;
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-small);
  line-height: 1.35;
  white-space: nowrap;
}

.project-grid-count-value {
  color: var(--itg-color-text-dark);
  font-weight: 600;
}

.project-grid-count-label {
  font-weight: 500;
}

.project-grid-page-size {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  flex-shrink: 0;
}

.project-grid-page-size .project-grid-field-label {
  margin: 0;
  white-space: nowrap;
}

.project-grid-page-size select {
  min-width: 4.75rem;
  border: 1px solid var(--itg-color-border);
  border-radius: 10px;
  padding: 0.55rem 0.75rem;
  font: inherit;
  font-size: var(--itg-font-size-small);
  color: var(--itg-color-text-dark);
  background: #fbfcfe;
  cursor: pointer;
}

.project-grid-page-size select:focus {
  outline: 2px solid rgba(15, 45, 82, 0.18);
  border-color: var(--itg-color-primary);
}

.project-grid-state,
.project-grid-empty {
  padding: 1.5rem;
  text-align: center;
  color: var(--itg-color-text-secondary);
}

.project-grid-state-error {
  color: var(--itg-color-error);
}

.project-grid-table-wrap {
  overflow-x: auto;
  border: 1px solid var(--itg-color-border);
  border-radius: 14px;
}

.project-grid-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  min-width: 900px;
}

.project-grid-table thead th {
  position: sticky;
  top: 0;
  z-index: 1;
  background: #f4f7fb;
  border-bottom: 1px solid var(--itg-color-border);
  padding: 1.05rem 1rem;
  color: var(--itg-color-primary);
  text-align: left;
  font-size: var(--itg-font-size-small);
  line-height: 1.35;
  vertical-align: bottom;
}

.project-grid-table thead th:first-child {
  border-top-left-radius: 12px;
}

.project-grid-table thead th:last-child {
  border-top-right-radius: 12px;
}

.project-grid-table thead th button {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  width: 100%;
  padding: 0;
  border: 0;
  background: transparent;
  color: inherit;
  font: inherit;
  font-weight: 700;
  cursor: pointer;
  text-align: inherit;
}

.project-grid-table thead th.project-grid-detail-col,
.project-grid-table thead th.project-grid-delete-col {
  text-align: center;
}

.project-grid-table thead th.project-grid-detail-col button {
  justify-content: center;
}

.project-grid-table thead th.project-grid-select-col {
  text-align: center;
  vertical-align: middle;
}

.project-grid-sort-indicator {
  font-size: 0.7rem;
  opacity: 0.85;
}



/* ---- table.css ---- */
.project-grid-table td {
  padding: 0.9rem 1rem;
  border-bottom: 1px solid #edf1f6;
  vertical-align: top;
  color: var(--itg-color-text-dark);
  font-size: var(--itg-font-size-small);
}

.project-grid-row {
  background: var(--itg-color-white);
}

.project-grid-row:hover {
  background: #fafcff;
}

.project-grid-row.is-selected {
  background: #eef4fb;
}

.project-grid-row.is-expanded {
  background: #f8fbff;
}

.project-grid-select-col,
.project-grid-detail-col,
.project-grid-delete-col {
  width: 88px;
  white-space: nowrap;
}

.project-grid-detail-button,
.project-grid-delete-button {
  border: 1px solid var(--itg-color-border);
  border-radius: 999px;
  padding: 0.45rem 0.75rem;
  font: inherit;
  font-size: 0.8rem;
  font-weight: 600;
  cursor: pointer;
  background: var(--itg-color-white);
  color: var(--itg-color-primary);
}

.project-grid-detail-button:disabled {
  cursor: not-allowed;
  opacity: 0.45;
}

.project-grid-delete-button {
  color: var(--itg-color-error);
}

.project-grid-detail-row td {
  background: #f8fbff;
}

.project-grid-detail-content {
  display: grid;
  gap: 0.6rem;
  color: var(--itg-color-text);
  line-height: var(--itg-line-height-meta);
}

.project-grid-pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 0.85rem;
  margin-top: 1rem;
  flex-wrap: wrap;
  color: var(--itg-color-text-secondary);
}

.project-grid-status {
  margin: 1rem 1.5rem 1.5rem;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-small);
}

.search-table-card {
  position: relative;
}

.search-table-card.is-delete-mode {
  border-color: rgba(179, 0, 0, 0.28);
  box-shadow: 0 12px 28px rgba(179, 0, 0, 0.14);
}

.search-table-delete-overlay {
  position: absolute;
  inset: 0;
  z-index: 3;
  border: 0;
  background: rgba(179, 0, 0, 0.08);
  color: var(--itg-color-error);
  font: inherit;
  font-weight: 700;
  cursor: pointer;
  backdrop-filter: blur(1px);
}

.past-projects-builder {
  display: grid;
  gap: 1.5rem;
}

.past-projects-action-bar {
  z-index: 5;
}

.past-projects-action-bar-controls {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.65rem 1.25rem;
  padding: 1rem 1.5rem 0;
}

.past-projects-action-bar-group {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.5rem;
}

@media (min-width: 641px) {
  .past-projects-action-bar-group + .past-projects-action-bar-group {
    padding-left: 1rem;
    border-left: 1px solid var(--itg-color-border);
  }
}

.past-projects-delete-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.7rem 0.9rem;
  border: 1px solid var(--itg-color-border);
  border-radius: 999px;
  background: #fbfcfe;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-small);
  font-weight: 600;
}

.past-projects-help-details {
  margin: 0.5rem 0 0;
  padding: 0.8rem 1.5rem 1.25rem;
  border: 0;
  border-top: 1px solid #edf1f6;
}

.past-projects-help-summary {
  cursor: pointer;
  list-style: none;
  padding: 0.15rem 0 0.25rem;
  font-size: var(--itg-font-size-small);
  font-weight: 600;
  color: var(--itg-color-primary);
  user-select: none;
}

.past-projects-help-summary::-webkit-details-marker {
  display: none;
}

.past-projects-help-summary::before {
  content: '▸';
  display: inline-block;
  margin-right: 0.4rem;
  font-size: 0.65rem;
  opacity: 0.75;
  transition: transform 0.15s ease;
}

.past-projects-help-details[open] .past-projects-help-summary::before {
  transform: rotate(90deg);
}

.past-projects-help-intro {
  margin: 0;
  padding: 0 0 0.65rem;
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-small);
  line-height: var(--itg-line-height-meta);
}

.past-projects-help-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.9rem;
  padding: 0.75rem 0 0;
  margin: 0;
}

.project-grid-help-card {
  display: grid;
  gap: 0.35rem;
  padding: 1rem;
  border-radius: 12px;
  background: #f6f9fc;
  color: var(--itg-color-text);
  font-size: var(--itg-font-size-small);
  line-height: var(--itg-line-height-meta);
}

.project-grid-help-card strong {
  color: var(--itg-color-primary);
}

@media (min-width: 641px) {
  .past-projects-help-grid .project-grid-help-card--wide {
    grid-column: 1 / -1;
  }
}

.search-table-stack {
  display: grid;
  gap: 1.5rem;
}

.project-grid-empty-shell {
  padding: 1.25rem;
}



/* ---- mobile.css ---- */
/* Mobile cards - hidden on desktop, shown on mobile */
.project-grid-mobile-cards {
  display: none;
}

.project-grid-mobile-card {
  border: 1px solid var(--itg-color-border);
  border-radius: 12px;
  padding: 1rem;
  background: var(--itg-color-white);
}

.project-grid-mobile-card + .project-grid-mobile-card {
  margin-top: 0.75rem;
}

.project-grid-mobile-card.is-expanded {
  background: #f8fbff;
}

.project-grid-mobile-card.is-selected {
  background: #eef4fb;
  border-color: var(--itg-color-primary);
}

.project-grid-mobile-card-select {
  margin-bottom: 0.5rem;
}

.project-grid-mobile-card-fields {
  display: grid;
  gap: 0.5rem;
}

.project-grid-mobile-card-field {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.project-grid-mobile-card-label {
  color: var(--itg-color-primary);
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.project-grid-mobile-card-value {
  color: var(--itg-color-text-dark);
  font-size: var(--itg-font-size-small);
  line-height: var(--itg-line-height-meta);
}

.project-grid-mobile-card-actions {
  display: flex;
  gap: 0.5rem;
  margin-top: 0.75rem;
}

.project-grid-mobile-card-actions .project-grid-detail-button,
.project-grid-mobile-card-actions .project-grid-delete-button {
  flex: 1;
  justify-content: center;
}

.project-grid-mobile-card-details {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--itg-color-border);
  display: grid;
  gap: 0.5rem;
  color: var(--itg-color-text);
  font-size: var(--itg-font-size-small);
  line-height: var(--itg-line-height-meta);
}



/* ---- responsive.css ---- */
@media (max-width: 900px) {
  .project-grid-card-header,
  .project-grid-table-shell {
    padding-left: 1rem;
    padding-right: 1rem;
  }

  .past-projects-action-bar-controls,
  .past-projects-help-details,
  .past-projects-help-grid {
    padding-left: 1rem;
    padding-right: 1rem;
  }

  .past-projects-help-grid {
    grid-template-columns: 1fr;
  }

  .project-grid-table thead th {
    position: static;
  }
}

@media (max-width: 768px) {
  /* Hide table, show mobile cards */
  .project-grid-table-wrap {
    display: none;
  }

  .project-grid-mobile-cards {
    display: block;
  }
}

@media (max-width: 640px) {
  .project-grid-controls-row {
    flex-direction: column;
    align-items: stretch;
  }

  .project-grid-controls-meta {
    justify-content: space-between;
    width: 100%;
  }

  .project-grid-inline-actions,
  .project-grid-toolbar {
    flex-direction: column;
    align-items: stretch;
  }

  .project-grid-inline-actions--clustered {
    align-items: stretch;
    gap: 0.65rem;
  }

  .project-grid-inline-actions--clustered .project-grid-toolbar-cluster {
    flex-direction: column;
    align-items: stretch;
    width: 100%;
    padding-left: 0;
    border-left: 0;
  }

  .project-grid-inline-actions--clustered .project-grid-toolbar-cluster + .project-grid-toolbar-cluster {
    padding-top: 0.65rem;
    border-top: 1px solid var(--itg-color-border);
  }

  .past-projects-action-bar-controls {
    flex-direction: column;
    align-items: stretch;
    gap: 0.65rem;
  }

  .past-projects-action-bar-group {
    width: 100%;
    flex-direction: column;
    align-items: stretch;
    padding-left: 0;
    border-left: 0;
  }

  .past-projects-action-bar-group + .past-projects-action-bar-group {
    padding-top: 0.65rem;
    border-top: 1px solid var(--itg-color-border);
  }

  .past-projects-action-bar {
    position: static;
  }

  .past-projects-delete-toggle {
    width: 100%;
    justify-content: center;
  }

  .past-projects-action-bar-group .itg-btn,
  .project-grid-toolbar-cluster .itg-btn {
    width: 100%;
    text-align: center;
  }

  .project-grid-card-header {
    padding: 1rem 1rem 0;
  }

  .project-grid-card-title {
    font-size: var(--itg-font-size-h2-mobile);
  }

  .project-grid-table-shell {
    padding: 0.75rem 0.5rem 1rem;
  }
}


/* ---- SheetsDataTable.css ---- */
.sdt-container {
  margin: 2rem 0;
}

.sdt-loading,
.sdt-error {
  padding: 2rem;
  text-align: center;
  color: var(--itg-color-text-secondary);
}

.sdt-error {
  color: var(--itg-color-error-light);
}

.sdt-controls {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
  gap: 1rem;
  flex-wrap: wrap;
}

.sdt-search {
  padding: 0.5rem 0.75rem;
  border: 1px solid var(--itg-color-border);
  border-radius: var(--itg-radius-button);
  font-size: var(--itg-font-size-meta);
  min-width: 250px;
}

.sdt-search:focus {
  outline: none;
  border-color: var(--itg-color-primary);
}

.sdt-count {
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-small);
}

.sdt-table-wrap {
  overflow-x: auto;
}

.sdt-table {
  width: 100%;
  border-collapse: collapse;
  font-size: var(--itg-font-size-small);
}

.sdt-th {
  background: var(--itg-color-bg-light);
  color: var(--itg-color-primary);
  padding: 0.625rem 0.5rem;
  text-align: left;
  border-bottom: 2px solid var(--itg-color-border);
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
}

.sdt-th:hover {
  background: #eef1f5;
}

.sdt-sorted-asc::after {
  content: ' \25B2';
  font-size: 0.625rem;
}

.sdt-sorted-desc::after {
  content: ' \25BC';
  font-size: 0.625rem;
}

.sdt-th-expand {
  width: 2rem;
  cursor: default;
}

.sdt-td {
  padding: 0.5rem;
  border-bottom: 1px solid var(--itg-color-border);
  color: var(--itg-color-text);
  vertical-align: top;
}

.sdt-td-expand {
  text-align: center;
  cursor: pointer;
  color: var(--itg-color-primary);
  font-size: 0.75rem;
}

.sdt-row-expanded .sdt-td {
  color: var(--itg-color-primary);
  font-weight: 600;
}

.sdt-detail-row .sdt-detail-cell {
  padding: 1rem 1.5rem;
  background: var(--itg-color-bg-light);
  border-bottom: 1px solid var(--itg-color-border);
}

.sdt-detail-section {
  color: var(--itg-color-text);
  line-height: var(--itg-line-height-meta);
  margin-bottom: 0.5rem;
}

.sdt-detail-section strong {
  color: var(--itg-color-primary);
}

.sdt-pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 1rem;
  margin-top: 1rem;
}

.sdt-page-btn {
  background: var(--itg-color-primary);
  color: var(--itg-color-white);
  border: none;
  padding: 0.4rem 1rem;
  border-radius: var(--itg-radius-button);
  cursor: pointer;
  font-size: var(--itg-font-size-small);
}

.sdt-page-btn:disabled {
  background: #ccc;
  cursor: not-allowed;
}

.sdt-page-info {
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-small);
}

@media (max-width: 768px) {
  .sdt-search {
    min-width: 100%;
  }

  .sdt-controls {
    flex-direction: column;
    align-items: stretch;
  }

  .sdt-table {
    font-size: var(--itg-font-size-table-mobile);
  }

  .sdt-th {
    padding: 0.5rem 0.4rem;
  }

  .sdt-td {
    padding: 0.4rem;
  }

  .sdt-detail-row .sdt-detail-cell {
    padding: 0.75rem 1rem;
  }
}

/* ---- layout.css ---- */
.event-reg-title {
  font-size: 1.75rem;
  font-weight: 700;
  color: #003366;
  margin: 0 0 0.5rem;
}

.event-reg-subtitle {
  font-size: 0.95rem;
  color: #6b7280;
  margin: 0 0 1.5rem;
}

/* Event info (shown whenever registration options are loaded — signed in or not) */
.event-reg-info {
  padding: 1.25rem;
  border-radius: 12px;
  background: #f8fafc;
  border: 1px solid #dbe3ef;
  margin-bottom: 1.5rem;
}

.event-reg-info h2 {
  margin: 0 0 0.75rem;
  font-size: 1.25rem;
  color: #003366;
}

.event-reg-info p {
  margin: 0.25rem 0;
  font-size: 0.9rem;
  color: #374151;
}

.event-reg-info p strong {
  color: #1f2937;
}

/* Auth inline section */
.event-reg-auth {
  padding: 1.5rem;
  border-radius: 12px;
  background: #fff;
  border: 1px solid #e5e7eb;
  margin-bottom: 1.5rem;
}

.event-reg-auth-hint {
  font-size: 0.85rem;
  color: #6b7280;
  margin: 0 0 1rem;
  line-height: 1.5;
}

/* Form elements (reuse auth patterns) */
.event-reg-form-group {
  margin-bottom: 1rem;
}

.event-reg-label {
  display: block;
  font-size: 0.85rem;
  font-weight: 600;
  color: #374151;
  margin-bottom: 0.375rem;
}

.event-reg-label .required-mark {
  color: #dc2626;
  margin-left: 0.125rem;
}

.event-reg-field-hint {
  margin: 0 0 0.375rem;
  font-size: 0.8rem;
  color: #6b7280;
  line-height: 1.4;
}

.event-reg-field-error {
  margin: 0.25rem 0 0;
  font-size: 0.8rem;
  color: #dc2626;
  line-height: 1.4;
}

.event-reg-form-group--error .event-reg-input,
.event-reg-form-group--error .event-reg-phone-region {
  border-color: #dc2626;
}

.event-reg-form-group--error .event-reg-input:focus,
.event-reg-form-group--error .event-reg-phone-region:focus {
  border-color: #dc2626;
  box-shadow: 0 0 0 3px rgba(220, 38, 38, 0.12);
}

.event-reg-form-group--error .event-reg-tickets {
  border: 1px solid #dc2626;
  border-radius: 10px;
  padding: 2px;
}

.event-reg-form-group--error .event-reg-label {
  color: #dc2626;
}

.event-reg-section-title {
  margin: 0 0 0.875rem;
  font-size: 1rem;
  font-weight: 700;
  color: #003366;
}

.event-reg-section-header {
  margin-bottom: 0.875rem;
}

.event-reg-section-header .event-reg-section-title {
  margin-bottom: 0.5rem;
}

.event-reg-section-card {
  margin-bottom: 1rem;
  padding: 1rem;
  border: 1px solid #dbe3ef;
  border-radius: 12px;
  background: #fff;
}

.event-reg-section-title--spaced {
  margin-top: 0;
}

.event-reg-section-card--spaced {
  margin-top: 1.25rem;
}

.event-reg-locked-note {
  margin: 0;
  padding: 0.75rem 0.875rem;
  border: 1px solid #dbeafe;
  border-radius: 8px;
  background: #eff6ff;
  color: #1e40af;
  font-size: 0.85rem;
  line-height: 1.45;
}

.event-reg-locked-link {
  color: #1d4ed8;
  font-weight: 700;
  text-decoration: underline;
}

.event-reg-locked-link:hover {
  color: #1e40af;
}

.event-reg-input {
  width: 100%;
  padding: 0.625rem 0.875rem;
  border: 1px solid #d1d5db;
  border-radius: 8px;
  font-size: 0.9rem;
  color: #1f2937;
  background: #fff;
  transition: border-color 0.15s;
  box-sizing: border-box;
}

.event-reg-input--editable {
  border-color: #93c5fd;
  background: #f8fbff;
}

.event-reg-input:disabled,
.event-reg-phone-region:disabled {
  background: #f9fafb;
  color: #6b7280;
  cursor: not-allowed;
}

.event-reg-org-toggle--editable .auth-org-toggle-btn {
  border-color: #93c5fd;
}

.event-reg-input:focus {
  outline: none;
  border-color: #003366;
  box-shadow: 0 0 0 3px rgba(0, 51, 102, 0.1);
}

.event-reg-textarea {
  resize: none;
  min-height: 72px;
  height: 72px;
}



/* ---- form.css ---- */
/* Ticket selection */
.event-reg-tickets {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.event-reg-ticket-option {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 10px;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s;
}

.event-reg-ticket-option:hover {
  border-color: #003366;
  background: #f0f4f8;
}

.event-reg-ticket-option.selected {
  border-color: #003366;
  background: #eef2f7;
}

.event-reg-ticket-option.sold-out {
  opacity: 0.5;
  cursor: not-allowed;
}

.event-reg-ticket-option input[type='radio'] {
  accent-color: #003366;
}

.event-reg-ticket-name {
  flex: 1;
  font-weight: 600;
  color: #1f2937;
}

.event-reg-ticket-meta {
  font-size: 0.8rem;
  color: #6b7280;
}

/* Profile form row (two columns) */
.event-reg-form-row {
  display: flex;
  gap: 1rem;
  margin-bottom: 1rem;
  align-items: flex-end;
}

.event-reg-form-row .event-reg-form-group {
  flex: 1;
  margin-bottom: 0;
  min-width: 0;
}

.event-reg-optional {
  font-weight: 400;
  color: #9ca3af;
  font-size: 0.8rem;
}

/* Phone input group */
.event-reg-phone-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  align-items: stretch;
}

.event-reg-phone-region {
  width: auto;
  min-width: 140px;
  flex-shrink: 0;
  padding: 0.625rem 0.5rem;
  border: 1px solid #d1d5db;
  border-radius: 8px;
  font-size: 0.85rem;
  color: #1f2937;
  background: #fff;
  box-sizing: border-box;
}

.event-reg-phone-region:focus {
  outline: none;
  border-color: #003366;
  box-shadow: 0 0 0 3px rgba(0, 51, 102, 0.1);
}

.event-reg-phone-row .event-reg-input {
  flex: 1 1 120px;
  min-width: 0;
}

.event-reg-phone-action {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.625rem 1rem;
  font-size: 0.85rem;
  font-weight: 600;
  white-space: nowrap;
  flex-shrink: 0;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: background 0.15s;
  background: #003366;
  color: #fff;
}

.event-reg-phone-action:hover:not(:disabled) {
  background: #002244;
}

.event-reg-phone-action:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.event-reg-phone-verified {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  color: #16a34a;
  font-weight: 600;
  font-size: 0.85rem;
  white-space: nowrap;
  flex-shrink: 0;
  padding: 0 0.5rem;
}

.event-reg-phone-code-row {
  display: flex;
  gap: 0.5rem;
  margin-top: 0.5rem;
}

.event-reg-phone-code-row .event-reg-input {
  flex: 1;
  font-family: 'Courier New', Courier, monospace;
  letter-spacing: 4px;
  font-size: 1.1rem;
  text-align: center;
}

/* Submit */
.event-reg-submit {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  width: 100%;
  padding: 0.75rem 1.5rem;
  font-size: 1rem;
  font-weight: 700;
  color: #111827;
  background: #daa520;
  border: none;
  border-radius: 10px;
  cursor: pointer;
  transition: background 0.15s;
  margin-top: 0.5rem;
}

.event-reg-submit:hover:not(:disabled) {
  background: #c49418;
}

.event-reg-submit:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}



/* ---- states.css ---- */
/* Confirmation / done */
.event-reg-done {
  text-align: center;
}

.event-reg-done h2 {
  font-size: 1.5rem;
  color: #003366;
  margin: 0 0 0.5rem;
}

.event-reg-done-subtitle {
  color: #6b7280;
  margin: 0 0 1.5rem;
  font-size: 0.95rem;
}

.event-reg-barcode {
  display: inline-block;
  max-width: 100%;
  border-radius: 8px;
  border: 1px solid #e5e7eb;
  padding: 12px;
  background: #fff;
}

.event-reg-ticket-code {
  font-size: 1.5rem;
  font-weight: 700;
  color: #003366;
  margin: 1rem 0 0.5rem;
  letter-spacing: 0.04em;
}

.event-reg-done-details {
  margin: 1rem auto;
  max-width: 360px;
  text-align: left;
  font-size: 0.9rem;
  color: #374151;
}

.event-reg-done-details p {
  margin: 0.25rem 0;
}

.event-reg-done-email-notice {
  margin: 1.5rem 0;
  padding: 0.75rem 1rem;
  border-radius: 8px;
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  color: #166534;
  font-size: 0.9rem;
}

.event-reg-done-email-error {
  margin: 1.5rem 0;
  padding: 0.75rem 1rem;
  border-radius: 8px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  color: #991b1b;
  font-size: 0.9rem;
}

.event-reg-link {
  display: inline-block;
  margin-top: 1rem;
  padding: 0.625rem 1.5rem;
  background: #003366;
  color: #fff;
  text-decoration: none;
  border-radius: 8px;
  font-weight: 600;
  font-size: 0.9rem;
}

.event-reg-link:hover {
  background: #002244;
}

/* Alert messages */
.event-reg-alert {
  padding: 0.75rem 1rem;
  border-radius: 8px;
  font-size: 0.9rem;
  margin-bottom: 1rem;
}

.event-reg-alert.error {
  background: #fef2f2;
  border: 1px solid #fecaca;
  color: #991b1b;
}

.event-reg-alert.info {
  background: #eff6ff;
  border: 1px solid #bfdbfe;
  color: #1e40af;
}

/* Loading */
.event-reg-loading {
  text-align: center;
  padding: 3rem 1rem;
  color: #6b7280;
}

.event-reg-loading--inline {
  padding: 1rem 1rem 0;
  font-size: 0.9rem;
}

/* Spinner */
.event-reg-spinner {
  display: inline-block;
  width: 16px;
  height: 16px;
  border: 2px solid currentColor;
  border-right-color: transparent;
  border-radius: 50%;
  animation: event-reg-spin 0.6s linear infinite;
}

@keyframes event-reg-spin {
  to { transform: rotate(360deg); }
}



/* ---- SchedulePage.css ---- */
.schedule-page {
  display: flex;
  flex-direction: column;
  gap: 2.5rem;
  padding-bottom: 2rem;
  color: var(--itg-color-primary);
}

.schedule-page-header {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.schedule-page-title {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-h1);
  font-weight: 800;
  letter-spacing: -0.03em;
}

.schedule-page-meta {
  margin: 0;
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-body);
  font-weight: 600;
}

.schedule-page-text,
.schedule-page-section-text {
  margin: 0;
  max-width: 64rem;
  color: var(--itg-color-text);
  font-size: var(--itg-font-size-body);
  line-height: var(--itg-line-height-body);
}

.schedule-page-section {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.schedule-page-section-title {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-subtitle);
  font-weight: 800;
  letter-spacing: -0.03em;
  text-align: center;
}

.schedule-page-section-title-main {
  margin-bottom: 0.25rem;
}

.schedule-page-section-stack {
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

.schedule-page-section-winners {
  gap: 1.5rem;
}

.schedule-winners-hero {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.6rem;
  width: min(100%, 760px);
  margin: 0 auto;
  padding: 0.2rem 1rem 0;
}

.schedule-winners-title {
  margin: 0;
  font-size: clamp(2rem, 4vw, 2.6rem);
  line-height: 1.05;
  letter-spacing: -0.04em;
  text-wrap: balance;
}

.schedule-winners-title-emphasis {
  color: #37a8ee;
}

.schedule-winners-title-event {
  color: var(--itg-color-primary);
}

.schedule-winners {
  display: flex;
  flex-direction: column;
  gap: 2.25rem;
}

.schedule-winners-group {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.6rem;
}

.schedule-winners-group-title {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: clamp(1.05rem, 2vw, 1.45rem);
  font-weight: 800;
  text-align: center;
}

.schedule-winners-grid {
  display: grid;
  width: min(100%, max-content);
  grid-template-columns: repeat(var(--winner-column-count, 1), minmax(180px, 1fr));
  gap: 0;
  align-items: stretch;
  margin: 0 auto;
}

.schedule-winner-card {
  display: flex;
  flex-direction: column;
  min-height: 9.25rem;
  border: 1px solid var(--itg-color-border);
  background: var(--schedule-column-bg);
  color: var(--schedule-cell-text);
  overflow: hidden;
  box-shadow: none;
}

.schedule-winner-card + .schedule-winner-card {
  border-left-width: 0;
}

.schedule-winner-card-header {
  padding: 0.8rem 1rem;
  background: #ececec;
  color: var(--itg-color-primary);
}

.schedule-winner-track {
  margin: 0;
  font-size: var(--itg-font-size-body);
  font-weight: 800;
}

.schedule-winner-card-body {
  display: flex;
  flex: 1;
  flex-direction: column;
  justify-content: stretch;
  gap: 0;
  background: var(--schedule-column-bg);
}

.schedule-winner-topic {
  margin: 0;
  padding: 0.8rem 1rem 0.7rem;
  color: var(--schedule-cell-text);
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  line-height: 1.25;
  border-bottom: 1px solid rgba(255, 255, 255, 0.6);
}

.schedule-winner-name {
  margin: 0;
  padding: 0.8rem 1rem 0.95rem;
  color: var(--schedule-cell-text);
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  line-height: 1.2;
}

.schedule-grand-winners {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  max-width: 100%;
}

.schedule-grand-winner-line {
  margin: 0;
  font-size: clamp(1.15rem, 1.9vw, 1.65rem);
  font-weight: 800;
  line-height: 1.2;
  text-align: center;
  text-wrap: balance;
}

.schedule-grand-winner-line.is-cap {
  color: #d2a820;
}

.schedule-grand-winner-line.is-cse {
  color: var(--itg-color-primary);
}

.schedule-grand-winner-line.is-cee,
.schedule-grand-winner-line.is-engsl {
  color: #2f8d8b;
}

.schedule-grand-winner-label {
  font-weight: 800;
}

.schedule-page-agenda-wrap,
.schedule-page-table-wrap {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

.schedule-page-agenda-table,
.schedule-presentation-table {
  width: 100%;
  min-width: 880px;
  border-collapse: separate;
  border-spacing: 1px;
  background: var(--itg-color-white);
}

.schedule-presentation-table {
  table-layout: fixed;
}

.schedule-page-agenda-table th,
.schedule-page-agenda-table td,
.schedule-presentation-table th,
.schedule-presentation-table td {
  padding: 0.95rem 0.85rem;
  vertical-align: top;
}

.schedule-page-agenda-table thead th,
.schedule-page-agenda-table tbody th,
.schedule-presentation-table thead th,
.schedule-presentation-table tbody th {
  background: #ececec;
  color: var(--itg-color-primary);
}

.schedule-page-agenda-table thead th,
.schedule-presentation-table thead th {
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  text-align: center;
}

.schedule-page-agenda-table tbody th,
.schedule-presentation-time {
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  text-align: left;
  white-space: nowrap;
}

.schedule-page-agenda-table td {
  background: #f5f5f5;
  color: var(--itg-color-primary);
  font-weight: 700;
  text-align: center;
}

.schedule-presentation-block {
  display: flex;
  flex-direction: column;
  gap: 0.9rem;
}

.schedule-presentation-heading {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-lead);
  font-weight: 800;
  text-align: center;
}

.schedule-presentation-corner,
.schedule-presentation-room,
.schedule-presentation-track {
  min-width: 0;
}

.schedule-presentation-corner {
  position: sticky;
  left: 0;
  z-index: 2;
}

.schedule-presentation-room,
.schedule-presentation-track {
  font-weight: 800;
}

.schedule-presentation-track {
  font-size: var(--itg-font-size-body);
}

.schedule-presentation-time {
  position: sticky;
  left: 0;
  z-index: 1;
}

.schedule-presentation-topic-cell,
.schedule-presentation-slot {
  background: var(--schedule-column-bg);
  color: var(--schedule-cell-text);
}

.schedule-presentation-topic-cell {
  font-weight: 800;
}

.schedule-presentation-topic {
  display: block;
  color: var(--schedule-topic-color);
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  line-height: 1.25;
}

.schedule-presentation-team,
.schedule-mobile-team {
  padding: 0;
  border: none;
  background: transparent;
  color: var(--schedule-cell-text);
  cursor: pointer;
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  line-height: 1.15;
  text-align: left;
  text-decoration: underline;
}

.schedule-presentation-team:hover,
.schedule-mobile-team:hover {
  opacity: 0.88;
}

.schedule-presentation-org,
.schedule-mobile-org {
  display: block;
  margin-top: 0.45rem;
  color: var(--schedule-org-color);
  font-size: var(--itg-font-size-small);
  line-height: 1.65;
}

.schedule-presentation-break,
.schedule-mobile-break {
  display: block;
  color: var(--schedule-cell-text);
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  text-align: center;
}

.schedule-presentation-slot-break {
  vertical-align: middle;
}

.schedule-presentation-empty,
.schedule-mobile-empty {
  color: var(--schedule-cell-text);
  font-size: var(--itg-font-size-small);
  font-weight: 600;
  opacity: 0.72;
}

.schedule-page-mobile-grid {
  display: none;
}

.schedule-mobile-card {
  border-radius: 0;
  overflow: hidden;
  border: 1px solid var(--itg-color-border);
  background: #f8fafc;
  box-shadow: 0 10px 30px rgba(16, 47, 100, 0.08);
}

.schedule-mobile-card-header {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: flex-start;
  padding: 1rem 1rem 0.9rem;
  background: #ececec;
}

.schedule-mobile-track-label {
  margin: 0 0 0.15rem;
  color: var(--itg-color-text-secondary);
  font-size: var(--itg-font-size-small);
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.schedule-mobile-topic {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-body);
  font-weight: 800;
  line-height: 1.2;
}

.schedule-mobile-room {
  margin: 0;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-small);
  font-weight: 700;
  white-space: nowrap;
}

.schedule-mobile-slots {
  display: flex;
  flex-direction: column;
}

.schedule-mobile-slot {
  display: grid;
  grid-template-columns: 4.25rem minmax(0, 1fr);
  min-height: 4.5rem;
}

.schedule-mobile-time {
  display: flex;
  align-items: flex-start;
  justify-content: flex-start;
  padding: 0.95rem 0.85rem;
  background: #ececec;
  color: var(--itg-color-primary);
  font-size: var(--itg-font-size-small);
  font-weight: 800;
}

.schedule-mobile-slot-content {
  padding: 0.95rem 1rem;
  background: var(--schedule-column-bg);
}

.schedule-mobile-slot + .schedule-mobile-slot {
  border-top: 1px solid rgba(255, 255, 255, 0.55);
}

.schedule-mobile-slot-content.is-break {
  display: flex;
  align-items: center;
  justify-content: center;
}

.schedule-page-state {
  border: 1px solid var(--itg-color-border);
  border-radius: 1rem;
  padding: 2rem;
  text-align: center;
  color: var(--itg-color-text-secondary);
  background: var(--itg-color-white);
}

.schedule-page-state-error {
  color: #b42318;
}

@media (max-width: 960px) {
  .schedule-page-agenda-table,
  .schedule-presentation-table {
    min-width: 760px;
  }

  .schedule-page {
    gap: 2rem;
  }
}

@media (max-width: 720px) {
  .schedule-page {
    gap: 1.75rem;
  }

  .schedule-page-header {
    gap: 0.4rem;
  }

  .schedule-page-title {
    font-size: var(--itg-font-size-h1-mobile);
  }

  .schedule-page-meta,
  .schedule-page-text,
  .schedule-page-section-text {
    font-size: var(--itg-font-size-small);
  }

  .schedule-page-agenda-table {
    min-width: 100%;
  }

  .schedule-page-agenda-table th,
  .schedule-page-agenda-table td {
    padding: 0.8rem 0.7rem;
  }

  .schedule-page-table-wrap-desktop {
    display: none;
  }

  .schedule-page-mobile-grid {
    display: grid;
    gap: 1rem;
  }

  .schedule-winners {
    gap: 1.75rem;
  }

  .schedule-winners-grid {
    grid-template-columns: 1fr;
    width: 100%;
  }

  .schedule-winner-card + .schedule-winner-card {
    border-left-width: 1px;
    border-top-width: 0;
  }

  .schedule-winners-title {
    font-size: var(--itg-font-size-h1-mobile);
  }

  .schedule-winners-hero {
    width: 100%;
    padding-inline: 0;
  }

  .schedule-grand-winner-line {
    font-size: var(--itg-font-size-lead);
  }

  .schedule-presentation-heading {
    font-size: var(--itg-font-size-body);
  }
}

@media (max-width: 480px) {
  .schedule-page-section-title {
