/* ---- tokens.css ---- */
/* MaintenanceMode - UC Merced Branded Maintenance Page */

/* UC Merced Brand Colors */
:root {
  --ucm-blue: #0f2d52;
  --ucm-blue-dark: #0a1f3a;
  --ucm-blue-light: #1a4a7a;
  --ucm-gold: #f2a900;
  --ucm-gold-light: #ffc107;
  --ucm-white: #ffffff;
  --ucm-gray: #f2f2f2;
  --ucm-text: #1f2933;
  --ucm-text-muted: #52606d;
  --ucm-border: #e4e7eb;
  --ucm-bg: #ffffff;
  --ucm-panel: #f3f4f6;
  --ucm-divider: #d9d9d9;
  --ucm-ok: #2ecc71;
  --ucm-error: #e74c3c;
}

.maintenance-container {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background: var(--ucm-blue);
  color: var(--ucm-white);
  font-family: 'Open Sans', 'Khula', -apple-system, BlinkMacSystemFont, sans-serif;
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 10000;
  overflow: auto;
}

.maintenance-shell {
  width: 100%;
  max-width: 980px;
  margin: auto;
  padding: 2.5rem 2rem;
  display: grid;
  grid-template-rows: 1fr auto;
  align-items: center;
  gap: 1.5rem;
  text-align: left;
  min-height: 100vh;
}

.maintenance-main {
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 1.5rem;
}

.maintenance-content {
  position: relative;
  z-index: 1;
  width: 100%;
  margin: 0;
}



/* ---- card.css ---- */
/* Main card */
.maintenance-card {
  display: flex;
  flex-direction: column;
  gap: 2.25rem;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.18);
  border-radius: 16px;
  padding: 2.75rem 3rem;
  -webkit-backdrop-filter: blur(6px);
  backdrop-filter: blur(6px);
}

/* Logo */

.maintenance-ucm-logo {
  height: 50px;
  width: auto;
  display: block;
}

.maintenance-i2g-logo {
  height: 44px;
  width: auto;
  display: block;
}

.maintenance-gear {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 60px;
  height: 60px;
  font-size: 50px;
  color: var(--ucm-gold);
  animation: maintenance-gear-rotate 6s linear infinite;
  margin-left: auto;
}

@keyframes maintenance-gear-rotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

/* Hero */
.maintenance-hero {
  margin-bottom: 0;
}

.maintenance-title-row {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  gap: 0.9rem;
  flex-wrap: wrap;
}

.maintenance-title {
  font-family: 'Open Sans', 'Khula', -apple-system, BlinkMacSystemFont, sans-serif;
  font-size: 3.125rem;
  font-weight: 700;
  margin: 0;
  letter-spacing: 0;
  color: var(--ucm-white);
  line-height: 3.125rem;
}

.maintenance-code {
  display: inline-flex;
  align-items: center;
  padding: 0.25rem 0.75rem;
  border: 1px solid rgba(255, 255, 255, 0.4);
  border-radius: 999px;
  font-size: 0.85rem;
  color: rgba(255, 255, 255, 0.85);
}

.maintenance-meta {
  margin: 0.6rem 0 0.35rem;
  font-size: 1rem;
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.9);
}

.maintenance-meta a {
  color: var(--ucm-gold);
  text-decoration: none;
}

.maintenance-meta a:hover {
  text-decoration: underline;
}

.maintenance-timestamp {
  margin: 0 0 0.5rem;
  font-size: 0.9rem;
  color: rgba(255, 255, 255, 0.7);
}

/* Alert */
.maintenance-alert {
  background: rgba(242, 169, 0, 0.1); /* ucm-gold with opacity */
  border: 1px solid var(--ucm-gold);
  border-radius: 8px;
  padding: 1.5rem;
  display: flex;
  align-items: flex-start;
  gap: 1rem;
  margin-bottom: 0.5rem;
}

.maintenance-alert-icon {
  color: var(--ucm-gold);
  font-size: 1.5rem;
  margin-top: 0.2rem;
}

.maintenance-alert-content h3 {
  margin: 0 0 0.5rem;
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--ucm-white);
}

.maintenance-alert-content p {
  margin: 0;
  font-size: 1rem;
  color: rgba(255, 255, 255, 0.9);
  line-height: 1.5;
}



/* ---- status.css ---- */
/* Status card */
.maintenance-status-card {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0;
  background: var(--ucm-panel);
  border: 1px solid var(--ucm-border);
  border-radius: 12px;
  padding: 1.75rem 1.5rem;
  margin: 0;
  position: relative;
  color: var(--ucm-text);
}

.status-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.8rem;
  text-align: center;
  padding: 0;
}

.status-item + .status-item {
  border-left: 1px solid var(--ucm-divider);
}

.status-logo-wrapper {
  width: 48px;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.status-logo {
  height: 36px;
  width: auto;
  display: block;
}

.status-logo-aws {
  height: 28px;
}

.status-title {
  font-size: 1.05rem;
  font-weight: 600;
  margin: 0;
  color: var(--ucm-text);
}

.status-subtitle {
  font-size: 0.98rem;
  color: var(--ucm-text-muted);
}

.status-subtitle-ok {
  color: #1f7a3b;
  font-weight: 700;
}

.status-subtitle-alert {
  color: #e74c3c;
  font-weight: 700;
}

/* Info sections */
.maintenance-info {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 3rem;
  padding-top: 1.75rem;
  border-top: 1px solid rgba(255, 255, 255, 0.3);
}

.maintenance-info h2 {
  margin: 0 0 0.75rem;
  font-size: 1.55rem;
  font-weight: 600;
  color: var(--ucm-white);
}

.maintenance-info p {
  margin: 0;
  font-size: 1.05rem;
  color: rgba(255, 255, 255, 0.8);
  line-height: 1.6;
}

/* Footer */
.maintenance-footer {
  width: 100%;
  padding: 0;
  z-index: 1;
}

.maintenance-footer-links {
  margin-bottom: 0.5rem;
}

.maintenance-footer-links a {
  color: rgba(255, 255, 255, 0.7);
  text-decoration: none;
  font-size: 0.85rem;
}

.maintenance-footer-links a:hover {
  color: var(--ucm-gold);
}

.footer-divider {
  margin: 0 0.75rem;
  color: rgba(255, 255, 255, 0.4);
}

.maintenance-copyright {
  margin: 0;
  font-size: 0.75rem;
  color: rgba(255, 255, 255, 0.55);
}



/* ---- forms.css ---- */
/* Bypass form */
.bypass-toggle-link {
  background: none;
  border: none;
  color: rgba(255, 255, 255, 0.7);
  font-size: 0.85rem;
  cursor: pointer;
  padding: 0;
  font-family: inherit;
  text-decoration: none;
}

.bypass-toggle-link:hover {
  color: var(--ucm-gold);
}

.bypass-form {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0.5rem 0;
  flex-wrap: wrap;
}

.bypass-input {
  padding: 0.35rem 0.65rem;
  border: 1px solid rgba(255, 255, 255, 0.3);
  border-radius: 4px;
  background: rgba(255, 255, 255, 0.1);
  color: var(--ucm-white);
  font-size: 0.85rem;
  font-family: inherit;
  outline: none;
  width: 180px;
}

.bypass-input::placeholder {
  color: rgba(255, 255, 255, 0.4);
}

.bypass-input:focus {
  border-color: var(--ucm-gold);
}

.bypass-input:disabled {
  opacity: 0.6;
}

.bypass-submit {
  padding: 0.35rem 0.85rem;
  border: 1px solid var(--ucm-gold);
  border-radius: 4px;
  background: var(--ucm-gold);
  color: var(--ucm-blue);
  font-size: 0.85rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
}

.bypass-submit:hover:not(:disabled) {
  background: var(--ucm-gold-light);
}

.bypass-submit:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.bypass-error {
  color: var(--ucm-error);
  font-size: 0.8rem;
}

/* Responsive */
@media (max-width: 640px) {
  .maintenance-header {
    margin: 0;
  }

  .maintenance-content {
    padding: 0;
  }

  .maintenance-title {
    font-size: 2rem;
    line-height: 2.2rem;
  }

  .maintenance-card {
    padding: 2rem 1.5rem;
  }

  .maintenance-status-card {
    grid-template-columns: 1fr;
    padding: 1.5rem;
  }

  .status-item + .status-item {
    border-left: none;
    border-top: 1px solid var(--ucm-divider);
    padding-top: 1.25rem;
  }

  .maintenance-info {
    grid-template-columns: 1fr;
    gap: 2rem;
  }

  .maintenance-footer-links a {
    font-size: 0.8rem;
  }
}


/* ---- HealthCheckProvider.css ---- */
@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
